buggy_code:
method CountArraysInSequence(seq: seq<array<int>>) returns (count: int)
    ensures count >= 0
    ensures count == |{ a: array<int> | a in seq && a != null }|
{
    var c := 0;
    var i := 0;
    while i < |seq|
        invariant 0 <= i <= |seq|
        invariant c >= 0
        invariant c == |{ a: array<int> | a in seq[..i] && a != null }|
    {
        if seq[i] != null {
            c := c + 1;
        }
        i := i + 1;
    }
    count := c;
}

fixed_code:
method CountArraysInSequence(se: seq<array<int>>) returns (count: int)
    modifies {}
    ensures count >= 0
//    ensures count == |{ a: array<int> | a in seq && a != null }|
    ensures count == |se|
//set a | a in se && a!= null && exists i :: 0 <= i < |se| && se[i] == a
{
    var c := 0;
    var i := 0;
    while i < |se|
        invariant 0 <= i <= |se|
        invariant c >= 0
        invariant c == |se[0..i]|
    {
        if se[i] != null {
            c := c + 1;
        }
        i := i + 1;
    }
    count := c;
}
